   283	/// Copy directory recursively, optionally preserving hardlinks
   284	fn copy_dir_contents(
   285	    from: &Path,
   286	    to: &Path,
   287	    #[cfg(unix)] hardlink_tracker: Option<&mut HardlinkTracker>,
   288	    #[cfg(unix)] hardlink_scanner: Option<&HardlinkGroupScanner>,
   289	    progress_bar: Option<&ProgressBar>,
   290	) -> io::Result<()> {
   291	    // Create the destination directory
   292	    fs::create_dir_all(to)?;
   293	
   294	    // Recursively copy contents
   295	    #[cfg(unix)]
   296	    {
   297	        if let (Some(tracker), Some(scanner)) = (hardlink_tracker, hardlink_scanner) {
   298	            copy_dir_contents_recursive(from, to, tracker, scanner, progress_bar)?;
   299	        }
   300	    }
   301	    #[cfg(not(unix))]
   302	    {
   303	        copy_dir_contents_recursive(from, to, progress_bar)?;
   304	    }
   305	
   306	    Ok(())
   307	}
   308	
   309	fn copy_dir_contents_recursive(
   310	    from_dir: &Path,
   311	    to_dir: &Path,
   312	    #[cfg(unix)] hardlink_tracker: &mut HardlinkTracker,
   313	    #[cfg(unix)] hardlink_scanner: &HardlinkGroupScanner,
   314	    progress_bar: Option<&ProgressBar>,
   315	) -> io::Result<()> {
   316	    let entries = fs::read_dir(from_dir)?;
   317	
   318	    for entry in entries {
   319	        let entry = entry?;
   320	        let from_path = entry.path();
   321	        let file_name = from_path.file_name().unwrap();
   322	        let to_path = to_dir.join(file_name);
   323	
   324	        if let Some(pb) = progress_bar {
   325	            pb.set_message(from_path.to_string_lossy().to_string());
   326	        }
   327	
   328	        if from_path.is_dir() {
   329	            // Recursively copy subdirectory
   330	            fs::create_dir_all(&to_path)?;
   331	            copy_dir_contents_recursive(
   332	                &from_path,
   333	                &to_path,
   334	                #[cfg(unix)]
   335	                hardlink_tracker,
   336	                #[cfg(unix)]
   337	                hardlink_scanner,
   338	                progress_bar,
   339	            )?;
   340	        } else {
   341	            // Copy file with or without hardlink support based on platform
   342	            #[cfg(unix)]
   343	            {
   344	                copy_file_with_hardlinks_helper(
   345	                    &from_path,
   346	                    &to_path,
   347	                    hardlink_tracker,
   348	                    hardlink_scanner,
   349	                )?;
   350	            }
   351	            #[cfg(not(unix))]
   352	            {
   353	                fs::copy(&from_path, &to_path)?;
   354	            }
   355	        }
   356	
   357	        if let Some(pb) = progress_bar {
   358	            if let Ok(metadata) = from_path.metadata() {
   359	                pb.inc(metadata.len());
   360	            }
   361	        }
   362	    }
   363	
   364	    Ok(())
   365	}
