   367	#[cfg(unix)]
   368	fn copy_file_with_hardlinks_helper(
   369	    from: &Path,
   370	    to: &Path,
   371	    hardlink_tracker: &mut HardlinkTracker,
   372	    hardlink_scanner: &HardlinkGroupScanner,
   373	) -> io::Result<()> {
   374	    // Check if this file should be a hardlink to an already-copied file
   375	    use crate::hardlink::HardlinkOptions;
   376	    let hardlink_options = HardlinkOptions::default();
   377	    // Create a hardlink instead of copying
   378	    if let Some(existing_target) =
   379	        hardlink_tracker.check_hardlink(from, to, hardlink_scanner, &hardlink_options)?
   380	    {
   381	        fs::hard_link(&existing_target, to)?;
   382	        return Ok(());
   383	    }
   384	
   385	    // Regular file copy
   386	    #[cfg(all(unix, not(any(target_os = "macos", target_os = "redox"))))]
   387	    {
   388	        fs::copy(from, to).and_then(|_| fsxattr::copy_xattrs(&from, &to))?;
   389	    }
   390	    #[cfg(any(target_os = "macos", target_os = "redox"))]
   391	    {
   392	        fs::copy(from, to)?;
   393	    }
   394	
   395	    Ok(())
   396	}
