   398	fn rename_file_fallback(
   399	    from: &Path,
   400	    to: &Path,
   401	    #[cfg(unix)] hardlink_tracker: Option<&mut HardlinkTracker>,
   402	    #[cfg(unix)] hardlink_scanner: Option<&HardlinkGroupScanner>,
   403	) -> io::Result<()> {
   404	    // Remove existing target file if it exists
   405	    if to.is_symlink() {
   406	        fs::remove_file(to).map_err(|err| {
   407	            let inter_device_msg = translate!("mv-error-inter-device-move-failed", "from" => from.display(), "to" => to.display(), "err" => err);
   408	            io::Error::new(err.kind(), inter_device_msg)
   409	        })?;
   410	    } else if to.exists() {
   411	        // For non-symlinks, just remove the file without special error handling
   412	        fs::remove_file(to)?;
   413	    }
   414	
   415	    // Check if this file is part of a hardlink group and if so, create a hardlink instead of copying
   416	    #[cfg(unix)]
   417	    {
   418	        if let (Some(tracker), Some(scanner)) = (hardlink_tracker, hardlink_scanner) {
   419	            use crate::hardlink::HardlinkOptions;
   420	            let hardlink_options = HardlinkOptions::default();
   421	            if let Some(existing_target) =
   422	                tracker.check_hardlink(from, to, scanner, &hardlink_options)?
   423	            {
   424	                // Create a hardlink to the first moved file instead of copying
   425	                fs::hard_link(&existing_target, to)?;
   426	                fs::remove_file(from)?;
   427	                return Ok(());
   428	            }
   429	        }
   430	    }
   431	
   432	    // Regular file copy
   433	    #[cfg(all(unix, not(any(target_os = "macos", target_os = "redox"))))]
   434	    fs::copy(from, to)
   435	        .and_then(|_| fsxattr::copy_xattrs(&from, &to))
   436	        .and_then(|_| fs::remove_file(from))
   437	        .map_err(|err| io::Error::new(err.kind(), translate!("mv-error-permission-denied")))?;
   438	    #[cfg(any(target_os = "macos", target_os = "redox", not(unix)))]
   439	    fs::copy(from, to)
   440	        .and_then(|_| fs::remove_file(from))
   441	        .map_err(|err| io::Error::new(err.kind(), translate!("mv-error-permission-denied")))?;
   442	    Ok(())
   443	}
