   449	/// Checks if a file can be deleted by attempting to open it with delete permissions.
   450	#[cfg(windows)]
   451	fn can_delete_file(path: &Path) -> bool {
   452	    use std::{
   453	        os::windows::ffi::OsStrExt as _,
   454	        ptr::{null, null_mut},
   455	    };
   456	
   457	    use windows_sys::Win32::{
   458	        Foundation::{CloseHandle, INVALID_HANDLE_VALUE},
   459	        Storage::FileSystem::{
   460	            CreateFileW, DELETE, FILE_ATTRIBUTE_NORMAL, FILE_SHARE_DELETE, FILE_SHARE_READ,
   461	            FILE_SHARE_WRITE, OPEN_EXISTING,
   462	        },
   463	    };
   464	
   465	    let wide_path = path
   466	        .as_os_str()
   467	        .encode_wide()
   468	        .chain([0])
   469	        .collect::<Vec<u16>>();
   470	
   471	    let handle = unsafe {
   472	        CreateFileW(
   473	            wide_path.as_ptr(),
   474	            DELETE,
   475	            FILE_SHARE_DELETE | FILE_SHARE_READ | FILE_SHARE_WRITE,
   476	            null(),
   477	            OPEN_EXISTING,
   478	            FILE_ATTRIBUTE_NORMAL,
   479	            null_mut(),
   480	        )
   481	    };
   482	
   483	    if handle == INVALID_HANDLE_VALUE {
   484	        return false;
   485	    }
   486	
   487	    unsafe { CloseHandle(handle) };
   488	
   489	    true
   490	}
   491	
   492	#[cfg(not(windows))]
   493	fn can_delete_file(_: &Path) -> bool {
   494	    // On non-Windows platforms, always return false to indicate that we don't need
   495	    // to try the copy+delete fallback. This is because on Unix-like systems,
   496	    // rename() failing with errors other than EXDEV means the operation cannot
   497	    // succeed even with a copy+delete approach (e.g. permission errors).
   498	    false
   499	}
